/*
 * hls.js placeholder — replace with the real bundle before deploying.
 *
 * Download from:
 *   https://cdn.jsdelivr.net/npm/hls.js@latest/dist/hls.min.js
 *
 * Or via the setup script:
 *   bash scripts/setup_camera.sh  (downloads automatically)
 *
 * This stub provides a minimal Hls shim so the rest of app.js
 * can load without throwing, and falls back to native HLS on Safari.
 */
(function(global) {
  'use strict';
  if (typeof global.Hls !== 'undefined') return;

  function Hls(config) {
    this._config = config || {};
    this._handlers = {};
  }
  Hls.isSupported = function() { return false; };
  Hls.Events = {
    MANIFEST_PARSED: 'hlsManifestParsed',
    ERROR: 'hlsError',
  };
  Hls.prototype.loadSource = function() {};
  Hls.prototype.attachMedia = function() {};
  Hls.prototype.on = function(event, fn) {
    this._handlers[event] = fn;
  };
  Hls.prototype.destroy = function() {};

  global.Hls = Hls;
})(window);
